/**
 * CRUD routes for projects.
 * Auto-generated by scaffold utility.
 */

import { readFile, writeFile, mkdir } from 'node:fs/promises';
import { join } from 'node:path';
import { randomUUID } from 'node:crypto';

const DATA_DIR = join(process.cwd(), 'data');
const DATA_FILE = join(DATA_DIR, 'projects.json');

async function loadAll() {
  try {
    const raw = await readFile(DATA_FILE, 'utf8');
    return JSON.parse(raw);
  } catch {
    return [];
  }
}

async function saveAll(records) {
  await mkdir(DATA_DIR, { recursive: true });
  await writeFile(DATA_FILE, JSON.stringify(records, null, 2) + '\n');
}

function validate(body, rules) {
  const errors = [];
  for (const [field, check] of Object.entries(rules)) {
    const value = body[field];
    if (check.required && (value === undefined || value === null || value === '')) {
      errors.push(`${field} is required.`);
    }
    if (check.type && value !== undefined && value !== null && typeof value !== check.type) {
      errors.push(`${field} must be a ${check.type}.`);
    }
  }
  return errors;
}

async function listProjects(req, res) {
  const records = await loadAll();
  res.json(records);
}

async function getProject(req, res) {
  const records = await loadAll();
  const record = records.find((r) => r.id === req.params.id);
  if (!record) {
    return res.status(404).json({ error: { code: 'NOT_FOUND', message: 'Project not found.' } });
  }
  res.json(record);
}

async function createProject(req, res) {
  const body = req.body || {};
  const errors = validate(body, {
    name: { required: true, type: 'string' }
  });
  if (errors.length) {
    return res.status(400).json({ error: { code: 'VALIDATION_ERROR', message: errors[0] } });
  }

  const record = {
    id: randomUUID(),
    name: body.name,
    description: body.description,
    deadline: body.deadline,
    team: body.team,
    status: body.status !== undefined ? body.status : 'active',
    createdAt: new Date().toISOString(),
  };

  const records = await loadAll();
  records.push(record);
  await saveAll(records);
  res.status(201).json(record);
}

async function updateProject(req, res) {
  const records = await loadAll();
  const index = records.findIndex((r) => r.id === req.params.id);
  if (index === -1) {
    return res.status(404).json({ error: { code: 'NOT_FOUND', message: 'Project not found.' } });
  }

  const body = req.body || {};
  const errors = validate(body, {
    name: { required: true, type: 'string' }
  });
  if (errors.length) {
    return res.status(400).json({ error: { code: 'VALIDATION_ERROR', message: errors[0] } });
  }

  const updated = { ...records[index], ...body, id: records[index].id };
  records[index] = updated;
  await saveAll(records);
  res.json(updated);
}

async function deleteProject(req, res) {
  const records = await loadAll();
  const index = records.findIndex((r) => r.id === req.params.id);
  if (index === -1) {
    return res.status(404).json({ error: { code: 'NOT_FOUND', message: 'Project not found.' } });
  }

  records.splice(index, 1);
  await saveAll(records);
  res.status(204).end();
}

export function registerProjectRoutes(router) {
  router.get('/projects', listProjects);
  router.get('/projects/:id', getProject);
  router.post('/projects', createProject);
  router.put('/projects/:id', updateProject);
  router.delete('/projects/:id', deleteProject);
}
